import json, sys, math, re

raw = json.load(sys.stdin)
if isinstance(raw, str):
    raw = json.loads(raw)

def unwrap(x):
    if isinstance(x, dict) and list(x.keys()) == ["result"]:
        return x["result"]
    if isinstance(x, dict) and "status" in x and "body" in x:
        return x["body"]
    return x

def walk(node):
    if isinstance(node, dict):
        yield node
        for v in node.values():
            yield from walk(v)
    elif isinstance(node, list):
        for v in node:
            yield from walk(v)

def clamp(x, lo=0, hi=100):
    return max(lo, min(hi, x))

def find_dependents(node):
    if isinstance(node, str) and len(node) > 100:
        m = re.search(r'([\d,]+)\s+Repositor', node)
        if m:
            return int(m.group(1).replace(",", ""))
    elif isinstance(node, dict):
        for v in node.values():
            r = find_dependents(v)
            if r is not None:
                return r
    elif isinstance(node, list):
        for v in node:
            r = find_dependents(v)
            if r is not None:
                return r
    return None

if isinstance(raw, dict) and "merged" in raw:
    raw = raw["merged"]
candidates = list(raw.values()) if isinstance(raw, dict) else raw

unwrapped = []
for v in candidates:
    u = unwrap(v)
    if isinstance(u, str):
        try:
            u = json.loads(u)
        except Exception:
            pass
    unwrapped.append(u)

# ── LLM narrative data ──────────────────────────────────────────────
llm = next(
    (u for u in walk(unwrapped) if isinstance(u, dict) and "enterprise_case_studies_score" in u),
    {}
)
ecs = float(llm.get("enterprise_case_studies_score") or 0)

# ── GitHub stars (raw API has stargazers_count) ─────────────────────
stars = next(
    (u.get("stargazers_count") for u in walk(unwrapped)
     if isinstance(u, dict) and "stargazers_count" in u),
    None
)

# ── GitHub dependents (extract from Playwright HTML) ────────────────
dependents = find_dependents(unwrapped)

# ── Stack Overflow question count ───────────────────────────────────
so_count = None
for u in walk(unwrapped):
    if isinstance(u, dict):
        items = u.get("items")
        if isinstance(items, list) and items and "count" in items[0]:
            so_count = items[0]["count"]
            break

# ── Score each sub-dimension (log scale, score 100 at ceiling) ─────
ecs_score   = clamp(ecs * 100)
stars_score = clamp(math.log10(max(stars, 1)) / math.log10(100_000) * 100) if stars is not None else None
so_score    = clamp(math.log10(max(so_count, 1)) / math.log10(50_000) * 100) if so_count is not None else None
dep_score   = clamp(math.log10(max(dependents, 1)) / math.log10(100_000) * 100) if dependents is not None else None

# ── Weighted average, renormalise over present dims only ───────────
pairs = [(v, w) for v, w in [
    (ecs_score,   0.35),
    (stars_score, 0.25),
    (so_score,    0.15),
    (dep_score,   0.25),
] if v is not None]
tw = sum(w for _, w in pairs)
production_score = round(sum(v * w for v, w in pairs) / tw, 1) if tw else None

result = {
    "enterprise_case_studies_score": ecs,
    "companies_in_production":       llm.get("companies_in_production", []),
    "use_cases":                     llm.get("use_cases", []),
    "scale_signals":                 llm.get("scale_signals", []),
    "reliability_signals":           llm.get("reliability_signals", []),
    "summary":                       llm.get("summary", ""),
    "github_stars":                  stars,
    "github_dependents":             dependents,
    "stackoverflow_question_count":  so_count,
    "sub_scores": {
        "case_studies":  round(ecs_score, 1),
        "stars":         round(stars_score, 1) if stars_score is not None else None,
        "stackoverflow": round(so_score, 1)    if so_score    is not None else None,
        "dependents":    round(dep_score, 1)   if dep_score   is not None else None,
    },
    "production_score": production_score,
}

print(json.dumps(result))

import json, sys, re

raw = json.load(sys.stdin)
if isinstance(raw, str):
    raw = json.loads(raw)

url = raw.get("github_url", "")
m = re.search(r"github\.com/([^/]+)/([^/]+?)(?:\.git)?$", url.strip())

if m:
    print(json.dumps({"owner": m.group(1), "repo": m.group(2)}))
else:
    print(json.dumps({"owner": "", "repo": ""}))
